mapper.select:
select *
from batch.job_task
where tenant_id = #{tenantId}
  and id = #{id}

select *
from batch.job_task
where tenant_id = #{tenantId}
  and job_partition_id = #{jobPartitionId}
  and task_seq = #{taskSeq}

select *
from batch.job_task
where tenant_id = #{tenantId}

    and job_instance_id = #{jobInstanceId}


    and job_partition_id = #{jobPartitionId}


    and task_status = #{taskStatus}

order by id desc

select *
from batch.job_task
where tenant_id = #{tenantId}
  and task_status = #{readyStatus}
order by id asc
limit #{batchSize}

select *
from batch.job_task
where tenant_id = #{tenantId}
  and assigned_worker_code = #{assignedWorkerCode}
  and task_status in (#{runningStatus}, #{readyStatus}, #{createdStatus})
order by id asc

mapper.update:
update batch.job_task
set assigned_worker_code = #{assignedWorkerCode},
    task_status = #{taskStatus},
    started_at = current_timestamp,
    version = version + 1,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}
  and task_status = #{readyStatus}
  and (assigned_worker_code is null or assigned_worker_code = #{assignedWorkerCode})
  and version = #{expectedVersion}

update batch.job_task
set task_status = #{toStatus},
    version = version + 1,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}
  and task_status = #{fromStatus}
  and version = #{expectedVersion}

update batch.job_task
set task_payload = #{taskPayload}::jsonb,
    version = version + 1,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}
